import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"34. Accident Pay","description":"","frontmatter":{"title":"34. Accident Pay","eba":"Medical Specialists 2022-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/wages/34-accident-pay.md","filePath":"ebas/medical-specialists/wages/34-accident-pay.md"}'),i={name:"ebas/medical-specialists/wages/34-accident-pay.md"};function r(c,e,s,p,h,l){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_34-accident-pay" tabindex="-1">34. Accident Pay <a class="header-anchor" href="#_34-accident-pay" aria-label="Permalink to &quot;34. Accident Pay&quot;">​</a></h1><p><strong>34.1</strong> Definitions</p><p><strong>(a)</strong> Accident Pay – total incapacity</p><p>Accident pay in respect of a Doctor deemed to be totally incapacitated under the WIRC Act means a weekly payment of an amount representing the difference between:</p><p><strong>(i)</strong> the total amount of compensation paid under WIRC Act for the week in question; and</p><p><strong>(ii)</strong> the amounts payable to the Doctor for ordinary hours for the week at the rates payable in accordance with <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> of this Agreement.</p><p><strong>(b)</strong> Accident Pay – partial incapacity</p><p><strong>(i)</strong> Accident pay in respect of a Doctor deemed to be partially incapacitated under the WIRC Act means a weekly payment of an amount representing the difference between:</p><p>A. the total amount of compensation paid under the WIRC Act for the period in question together with the average weekly amount the Doctor is earning or is able to earn in some suitable employment or business (as determined expressly or by implication by the WorkCover Authority or as agreed between the parties); and</p><p>B. the amounts payable to the Doctor for ordinary hours for the week at the rates payable in accordance with</p><p><strong>(ii)</strong> The rate will be the same as that applying for a total incapacity. However, where the Doctor receives a weekly payment under this clause and the payment is subsequently reduced pursuant to the WIRC Act, the reduction will not increase the liability of the Health Service to increase the amount of accident pay in respect of that injury.</p><p><strong>(iii)</strong> Where a Doctor receives accident pay and the pay is payable for incapacity for part of a week, the amount will be a direct proportion.</p><p><strong>(c)</strong> Injury</p><p>Injury has the same meaning and application as applying under the WIRC Act. No injury will result in the application of accident pay unless an entitlement exists under the WIRC Act.</p><p><strong>34.2</strong> Entitlement to Accident Pay</p><p><strong>(a)</strong> A Health Service will pay a Doctor accident pay where the Doctor receives payment in respect of a weekly incapacity (within the meaning of the WIRC Act) in respect of which the Health Service is liable to pay compensation under the WIRC Act. The Health Service’s liability to pay accident pay may be discharged by another person on the Health Service’s behalf.</p><p><strong>(b)</strong> Accident pay does not apply:</p><p><strong>(i)</strong> for the first five normal working days of incapacity, except where a Doctor contracts an infectious disease in the course of duty and is entitled to receive workers compensation (in which case the Doctor will receive accident pay from the first day of incapacity);</p><p><strong>(ii)</strong> to any incapacity occurring during the first two weeks of employment, unless incapacity continues beyond this time. Subject to subclauses 34.2(b)(i) and 34.4 accident pay will only apply to the period of incapacity after the first two weeks of employment;</p><p><strong>(iii)</strong> to industrial diseases contracted by a gradual process or injuries subject to recurrence, aggravation or acceleration (as determined by the WIRC Act) unless the Doctor has been employed with the Health Service at the time of the incapacity for a minimum period of one month.</p><p><strong>(c)</strong> A Doctor on engagement may be required to declare all workers compensation claims made in the previous five years. In the event of false or inaccurate information being knowingly declared by the Doctor the Health Service is entitled to require the Doctor to forfeit his or her entitlement to accident pay under this clause.</p><p><strong>34.3</strong> Cessation of Accident Pay</p><p><strong>(a)</strong> A Doctor&#39;s entitlement to accident pay ceases:</p><p><strong>(i)</strong> when the incapacity ceases;</p><p><strong>(ii)</strong> on the death of the Doctor;</p><p><strong>(iii)</strong> when the Doctor has received a total of 39 weeks’ accident pay for any one injury;</p><p><strong>(iv)</strong> when there is a cessation or redemption of weekly compensation payments under the WIRC Act, in which case accident pay will cease from the date of such cessation or redemption; or</p><p><strong>(v)</strong> where a Doctor refuses or fails to commence work after a medical referee, in accordance with the WIRC Act, has given a certificate specifying work for which the Doctor is fit and the Health Service makes this work available to the Doctor, in which case accident pay will cease from the date of the refusal or failure to commence work.</p><p><strong>34.4</strong> Termination of employment</p><p><strong>(a)</strong> Subject to subclauses 34.3, 34.4(c) and 34.4(d) of this Agreement, a Doctor&#39;s entitlement to accident pay will continue on termination of employment by his or her Health Service, if the Doctor was incapacitated and receiving accident pay at the date of termination.</p><p><strong>(b)</strong> A Doctor with partial incapacity will continue to receive accident pay from their Health Service on termination of his or her employment if:</p><p><strong>(i)</strong> the Health Service cannot provide suitable employment for the Doctor to perform; and</p><p><strong>(ii)</strong> alternative employment is available with another Health Service.</p><p><strong>(c)</strong> To qualify for the continuance of accident pay on termination of employment, a Doctor will provide evidence to his or her Health Service of the continuing payment of weekly workers compensation payments.</p><p><strong>(d)</strong> A Doctor&#39;s entitlement to accident pay on termination of his or her employment will cease if the termination is due to serious and/or wilful misconduct on the part of the Doctor.</p><p><strong>34.5</strong> Absences on other paid leave</p><p>A Doctor is not entitled to payment for accident pay in respect of any period of other paid leave of absence.</p><p><strong>34.6</strong> Notice of injury</p><p>A Doctor, on receiving an injury for which the Doctor claims to be entitled to receive accident pay, will give notice in writing of the injury to the Health Service as soon as reasonably practicable after the occurrence of the injury. Notice may be given by a representative of the Doctor.</p><p><strong>34.7</strong> Medical examination</p><p>To receive an entitlement to accident pay, a Doctor will conform to the requirements of the WIRC Act as to medical examinations.</p><p><strong>34.8</strong> Civil damages claims</p><p><strong>(a)</strong> A Doctor receiving or who has received accident pay will advise his or her Health Service of any action the Doctor may institute or any claim the Doctor may make for damages. The Doctor, if requested, will provide an authority to the Health Service entitling the Health Service to a charge upon any money payable pursuant to any judgment or settlement on that injury.</p><p><strong>(b)</strong> Where a Doctor obtains a judgment or settlement for damages in respect of an injury for which they have received accident pay, the Health Service’s liability to pay accident pay will cease from the date of judgment or settlement. However, if the judgment or settlement for damages is not reduced, either in whole or in part, by the amount of accident pay made by the Health Service, the Doctor will pay to the Health Service any amount of accident pay already received in respect of that injury by which the judgment or settlement has not been reduced.</p><p><strong>(c)</strong> Where a Doctor obtains a judgment or settlement for damages against a person other than the Health Service in respect of an injury for which the Doctor has received accident pay, the Health Service’s liability to pay accident pay will cease from the date of judgment or settlement. However if the judgment or settlement for damages is not reduced either in whole or part by the amount of accident pay made by the Health Service, the Doctor will pay to the Health Service any amount of accident pay already received in respect of that injury by which the judgment or settlement has not been reduced.</p><p><strong>34.9</strong> Variation in compensation rates</p><p>Any changes in compensation rates under the WIRC Act will not increase the amount of accident pay above the amount that would have been payable had the rates of compensation remained unchanged.</p><p><strong>34.10</strong> Insurance against liability</p><p>Nothing in this Agreement requires a Health Service to insure against liability for accident pay.</p>',49)])])}const m=t(i,[["render",r]]);export{y as __pageData,m as default};
